import logging
from dataclasses import dataclass
from typing import Dict
import unittest

# Configure logging for production-ready output
logging.basicConfig(level=logging.INFO, format='%(levelname)s: %(message)s')
logger = logging.getLogger(__name__)

@dataclass
class Product:
    """Represents an inventory item."""
    product_id: str
    name: str
    _quantity: int = 0

    @property
    def quantity(self) -> int:
        return self._quantity

    @quantity.setter
    def quantity(self, value: int):
        if value < 0:
            raise ValueError(f"Stock quantity cannot be negative. Attempted: {value}")
        self._quantity = value

class InventoryManager:
    """Service layer for managing inventory operations."""
    LOW_STOCK_THRESHOLD = 5

    def __init__(self):
        self._products: Dict[str, Product] = {}

    def add_product(self, product: Product) -> None:
        """Adds a new product to the inventory."""
        if product.product_id in self._products:
            raise ValueError(f"Product ID {product.product_id} already exists.")
        self._products[product.product_id] = product

    def update_stock(self, product_id: str, amount: int) -> None:
        """Updates stock count and triggers alert if below threshold."""
        if product_id not in self._products:
            raise KeyError(f"Product ID {product_id} not found.")

        product = self._products[product_id]
        new_quantity = product.quantity + amount

        # Setter validation handles negative check
        product.quantity = new_quantity

        if product.quantity < self.LOW_STOCK_THRESHOLD:
            logger.warning(f"LOW STOCK ALERT: {product.name} (ID: {product_id}) is at {product.quantity}")

class TestInventoryManager(unittest.TestCase):
    def setUp(self):
        self.manager = InventoryManager()
        self.manager.add_product(Product("P1", "Widget", 10))

    def test_add_duplicate_product(self):
        with self.assertRaises(ValueError):
            self.manager.add_product(Product("P1", "Duplicate", 5))

    def test_update_nonexistent_product(self):
        with self.assertRaises(KeyError):
            self.manager.update_stock("INVALID", 5)

    def test_negative_stock_prevention(self):
        with self.assertRaises(ValueError):
            self.manager.update_stock("P1", -20)

    def test_low_stock_threshold(self):
        # Current is 10, subtract 6 to reach 4 (below 5)
        with self.assertLogs(logger, level='WARNING') as cm:
            self.manager.update_stock("P1", -6)
            self.assertTrue(any("LOW STOCK ALERT" in output for output in cm.output))

if __name__ == "__main__":
    unittest.main()
